import React from 'react';
import PropTypes from 'prop-types';
import { WARNING_ALT_ATTRIBUTE } from '../constants/warnings';

/** @type {typeof import('../..').Image} */
const Image = ({ className, width, height, src, src2x, title }) => (
  // eslint-disable-next-line nordic/no-img-tags
  <img
    className={className}
    width={width}
    height={height}
    src={src}
    alt={title}
    srcSet={src2x && `${src} 1x, ${src2x} 2x`}
  />
);

/** @type {import('prop-types').Validator<string>} */
const checkTitleProp = ({ title }, propName, componentName) => {
  PropTypes.checkPropTypes({ title: PropTypes.string }, { title }, propName, componentName);
  return typeof title === 'undefined' ? new Error(WARNING_ALT_ATTRIBUTE) : null;
};

Image.propTypes = {
  title: checkTitleProp,
  src: PropTypes.string,
  src2x: PropTypes.string,
  width: PropTypes.string,
  height: PropTypes.string,
  className: PropTypes.string,
};

export default Image;

